// QUEUE와 TAXONOMY 데이터 가져오기
const queueItems = $items('Read Existing QUEUE');
const taxonomyItems = $items('Read TAXONOMY');

// 에러 체크
if (!queueItems || queueItems.length === 0) {
  throw new Error('Failed to read QUEUE data from Google Sheets');
}
if (!taxonomyItems || taxonomyItems.length === 0) {
  throw new Error('Failed to read TAXONOMY data from Google Sheets');
}

// TAXONOMY에서 각 컬럼의 허용 값 추출
const taxonomy = {};
const columns = ['status', 'priority', 'category', 'target_type', 'content_type', 'search_intent', 'language', 'geo_scope', 'monetization_path', 'freshness_level', 'source_needed', 'internal_cluster', 'subcategory'];

columns.forEach(col => {
  taxonomy[col] = taxonomyItems
    .map(item => item.json[col])
    .filter(v => v !== undefined && v !== null && String(v).trim() !== '')
    .map(v => String(v).trim());
});

// 기존 QUEUE에서 이미 다룬 키워드들 추출
const existingKeywords = queueItems
  .map(item => item.json.seed_keyword || '')
  .filter(k => k.trim() !== '')
  .map(k => k.toLowerCase().trim());

const existingCategories = queueItems
  .map(item => item.json.category || '')
  .filter(c => c.trim() !== '');

// 카테고리별 콘텐츠 수 계산
const categoryCounts = {};
existingCategories.forEach(cat => {
  categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
});

// 가장 적게 다룬 카테고리 찾기
const validCategories = taxonomy.category || [];
const underrepresented = validCategories
  .map(cat => ({ category: cat, count: categoryCounts[cat] || 0 }))
  .sort((a, b) => a.count - b.count)
  .slice(0, 3)
  .map(c => c.category);

// 최근 추가된 키워드 샘플 (중복 방지용)
const recentKeywordsSample = existingKeywords.slice(-50).join(', ');

return [{
  json: {
    existing_keywords_sample: recentKeywordsSample,
    underrepresented_categories: underrepresented.join(', '),
    total_queue_count: queueItems.length,
    category_distribution: JSON.stringify(categoryCounts),
    taxonomy: JSON.stringify(taxonomy)
  }
}];

// TAXONOMY 데이터 가져오기 (검증용)
const analysisData = $items('Analyze Queue & Taxonomy')[0]?.json || {};
const taxonomy = JSON.parse(analysisData.taxonomy || '{}');

// Anthropic API 응답에서 텍스트 추출
const response = $input.first().json;
let content = '';

// 에러 체크
if (response.error) {
  throw new Error(`Claude API Error: ${response.error.message || JSON.stringify(response.error)}`);
}

// Anthropic API 응답 형식: { content: [{ type: 'text', text: '...' }] }
if (response.content && Array.isArray(response.content)) {
  const textBlock = response.content.find(block => block.type === 'text');
  content = textBlock?.text || '';
} else if (typeof response === 'string') {
  content = response;
} else {
  content = JSON.stringify(response);
}

if (!content || content.trim() === '') {
  throw new Error('Claude API returned empty response');
}

function extractJson(text) {
  const cleaned = String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON found in Claude response');
  return JSON.parse(cleaned.slice(first, last + 1));
}

// 값 검증 함수
function validateField(value, allowedValues, fieldName, defaultValue) {
  if (!allowedValues || allowedValues.length === 0) return value || defaultValue;
  const strValue = String(value || '').trim();
  if (allowedValues.includes(strValue)) return strValue;
  // 대소문자 무시 매칭 시도
  const lowerValue = strValue.toLowerCase();
  const match = allowedValues.find(v => v.toLowerCase() === lowerValue);
  if (match) return match;
  console.log(`Warning: Invalid ${fieldName} '${value}', using default '${defaultValue}'`);
  return defaultValue;
}

const data = extractJson(content);

if (!data.topics || !Array.isArray(data.topics)) {
  throw new Error('Invalid response: topics array not found');
}

if (data.topics.length === 0) {
  throw new Error('Claude returned empty topics array');
}

const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const generatedAt = new Date().toISOString();
const discoveryTheme = data.discovery_theme || '';

// 기본값 설정
const defaults = {
  category: taxonomy.category?.[0] || 'Housing',
  target_type: taxonomy.target_type?.[0] || 'newcomer',
  content_type: taxonomy.content_type?.[0] || 'how-to',
  search_intent: taxonomy.search_intent?.[0] || 'informational',
  language: 'en',
  geo_scope: taxonomy.geo_scope?.[0] || 'Korea',
  monetization_path: taxonomy.monetization_path?.[0] || 'adsense',
  freshness_level: taxonomy.freshness_level?.[0] || 'low',
  source_needed: taxonomy.source_needed?.[0] || 'no',
  internal_cluster: taxonomy.internal_cluster?.[0] || 'visa',
  subcategory: taxonomy.subcategory?.[0] || 'renting'
};

// 각 토픽을 개별 아이템으로 변환 (TAXONOMY 검증 적용)
return data.topics.map((topic, idx) => {
  const topicId = `KRY-AUTO-${today}-${String(idx + 1).padStart(3, '0')}`;

  // SEO 타이틀에서 특수문자 제거
  let cleanTitle = (topic.seo_title_hint || '').replace(/[:*#|\[\]"'\-\u2013\u2014]/g, '').replace(/\s+/g, ' ').trim();

  // priority 검증 (1-5)
  let priority = parseInt(topic.priority) || 3;
  if (priority < 1) priority = 1;
  if (priority > 5) priority = 5;

  return {
    json: {
      topic_id: topicId,
      status: 'queued',
      priority: priority,
      category: validateField(topic.category, taxonomy.category, 'category', defaults.category),
      subcategory: validateField(topic.subcategory, taxonomy.subcategory, 'subcategory', defaults.subcategory),
      seed_keyword: topic.seed_keyword || '',
      problem_angle: topic.problem_angle || '',
      target_type: validateField(topic.target_type, taxonomy.target_type, 'target_type', defaults.target_type),
      content_type: validateField(topic.content_type, taxonomy.content_type, 'content_type', defaults.content_type),
      search_intent: validateField(topic.search_intent, taxonomy.search_intent, 'search_intent', defaults.search_intent),
      language: validateField(topic.language || 'en', taxonomy.language, 'language', defaults.language),
      geo_scope: validateField(topic.geo_scope || 'Korea', taxonomy.geo_scope, 'geo_scope', defaults.geo_scope),
      monetization_path: validateField(topic.monetization_path, taxonomy.monetization_path, 'monetization_path', defaults.monetization_path),
      freshness_level: validateField(topic.freshness_level, taxonomy.freshness_level, 'freshness_level', defaults.freshness_level),
      source_needed: validateField(topic.source_needed, taxonomy.source_needed, 'source_needed', defaults.source_needed),
      source_note: topic.source_note || '',
      internal_cluster: validateField(topic.internal_cluster, taxonomy.internal_cluster, 'internal_cluster', defaults.internal_cluster),
      seo_title_hint: cleanTitle,
      note: `[Auto-discovered] ${topic.note || ''} | Theme: ${discoveryTheme}`,
      retry_count: 0,
      qa_score: '',
      qa_decision: '',
      published_url: '',
      last_error: '',
      next_retry_at: ''
    }
  };
});

// 기존 QUEUE 데이터 가져오기
const queueItems = $items('Read Existing QUEUE');
const newTopics = $input.all();

// 기존 키워드 추출 (전체)
const existingKeywords = queueItems
  .map(item => (item.json.seed_keyword || '').toLowerCase().trim())
  .filter(k => k !== '');

// 기존 SEO 타이틀 추출
const existingSeoTitles = queueItems
  .map(item => (item.json.seo_title_hint || '').toLowerCase().trim())
  .filter(t => t !== '');

// 불용어 (비교시 제외)
const stopWords = new Set(['how', 'to', 'in', 'korea', 'korean', 'for', 'foreigners', 'the', 'a', 'an', 'and', 'or', 'of', 'is', 'are', 'what', 'when', 'where', 'why', 'can', 'do', 'does', 'your', 'my', 'as']);

// 핵심 단어 추출 함수
function extractCoreWords(text) {
  return text.toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.has(w));
}

// 유사도 체크 함수 (Jaccard 유사도)
function calculateSimilarity(words1, words2) {
  if (words1.length === 0 || words2.length === 0) return 0;
  const set1 = new Set(words1);
  const set2 = new Set(words2);
  const intersection = [...set1].filter(w => set2.has(w)).length;
  const union = new Set([...set1, ...set2]).size;
  return intersection / union;
}

// 중복 체크 및 필터링
const uniqueTopics = [];
const duplicates = [];

for (const topic of newTopics) {
  const newKeyword = (topic.json.seed_keyword || '').toLowerCase().trim();
  const newTitle = (topic.json.seo_title_hint || '').toLowerCase().trim();
  const newCoreWords = extractCoreWords(newKeyword + ' ' + newTitle);

  let isDuplicate = false;
  let duplicateReason = '';

  // 1. 정확히 일치하는 키워드 체크
  if (existingKeywords.includes(newKeyword)) {
    isDuplicate = true;
    duplicateReason = `Exact keyword match: "${newKeyword}"`;
  }

  // 2. 기존 키워드와 유사도 체크 (70% 이상이면 중복)
  if (!isDuplicate) {
    for (const existing of existingKeywords) {
      const existingCoreWords = extractCoreWords(existing);
      const similarity = calculateSimilarity(newCoreWords, existingCoreWords);
      if (similarity >= 0.7) {
        isDuplicate = true;
        duplicateReason = `Similar to existing (${Math.round(similarity * 100)}%): "${existing}"`;
        break;
      }
    }
  }

  // 3. 기존 SEO 타이틀과 유사도 체크
  if (!isDuplicate) {
    for (const existingTitle of existingSeoTitles) {
      const existingCoreWords = extractCoreWords(existingTitle);
      const similarity = calculateSimilarity(newCoreWords, existingCoreWords);
      if (similarity >= 0.7) {
        isDuplicate = true;
        duplicateReason = `Similar SEO title (${Math.round(similarity * 100)}%): "${existingTitle}"`;
        break;
      }
    }
  }

  // 4. 이번 배치 내 중복 체크
  if (!isDuplicate) {
    for (const accepted of uniqueTopics) {
      const acceptedKeyword = (accepted.json.seed_keyword || '').toLowerCase().trim();
      const acceptedCoreWords = extractCoreWords(acceptedKeyword);
      const similarity = calculateSimilarity(newCoreWords, acceptedCoreWords);
      if (similarity >= 0.7) {
        isDuplicate = true;
        duplicateReason = `Duplicate within batch: "${acceptedKeyword}"`;
        break;
      }
    }
  }

  if (isDuplicate) {
    duplicates.push({
      keyword: newKeyword,
      reason: duplicateReason
    });
  } else {
    uniqueTopics.push(topic);
  }
}

// 로그 출력
console.log('=== Duplicate Filter Results ===');
console.log(`Total new topics: ${newTopics.length}`);
console.log(`Unique topics: ${uniqueTopics.length}`);
console.log(`Filtered duplicates: ${duplicates.length}`);
duplicates.forEach(d => console.log(`  - ${d.keyword}: ${d.reason}`));

// 유니크한 토픽만 반환 (없으면 빈 배열)
if (uniqueTopics.length === 0) {
  // 모두 중복이면 빈 아이템 반환 (워크플로우 계속 진행되도록)
  return [];
}

return uniqueTopics;

