// 에러 정보 수집
const errorInfo = {
  failedNode: $execution.customData?.get?.('lastNode') || 'Unknown',
  errorMessage: 'Workflow execution failed',
  executionId: $execution.id,
  timestamp: new Date().toISOString(),
  mode: $execution.mode
};

// 이전 노드들의 에러 확인
try {
  const allItems = $input.all();
  if (allItems.length > 0) {
    const lastItem = allItems[allItems.length - 1];
    if (lastItem.json?.error) {
      errorInfo.errorMessage = lastItem.json.error.message || JSON.stringify(lastItem.json.error);
    }
  }
} catch (e) {
  errorInfo.errorMessage = e.message || 'Unknown error';
}

return [{ json: errorInfo }];
